import os
import logging

# Set up logging
logging.basicConfig(filename='file_cleanup.log', level=logging.INFO, format='%(asctime)s - %(message)s')

def get_user_input():
    """Prompt the user for the username and home directory."""
    username = input("Enter the username: ")
    home_dir = os.path.join('/home', username)
    return home_dir

def traverse_directory(directory):
    """Recursively traverse the directory and its subdirectories."""
    for item in os.listdir(directory):
        item_path = os.path.join(directory, item)
        if os.path.isdir(item_path):
            try:
                traverse_directory(item_path)
            except Exception as e:
                logging.error(f"Error traversing {item_path}: {e}")
        else:
            try:
                if item == '.Trash-1000' or item == '.Trash':
                    logging.info(f"Skipping.Trash-1000 and.Trash directories")
                    continue
                elif item == 'Thumbs.db' or item == '.DS_Store':
                    logging.info(f"Skipping Thumbs.db and.DS_Store files")
                    continue
                elif not os.path.isfile(item_path):
                    logging.info(f"Skipping non-file {item}")
                    continue
                else:
                    logging.info(f"Processing {item_path}")
                    confirm_deletion = input(f"Delete {item_path}? (y/n): ")
                    if confirm_deletion.lower() == 'y':
                        try:
                            os.remove(item_path)
